 *
 * @author Dhiraj
 */
@RestController
@RequestMapping("/v1")
@RequiredArgsConstructor
public class AuthController {

  private final AuthClient authClient;

  @PostMapping(
      value = "/token/authenticate",
      produces = MediaType.APPLICATION_JSON_VALUE,
      consumes = MediaType.APPLICATION_JSON_VALUE)
  public ResponseEntity<AuthResponseDTO> authenticateUser(
      @RequestBody @Valid AuthRequestDTO authDTO) {
    return ResponseEntity.ok(authClient.authenticate(authDTO));
  }

  @PostMapping(
      value = "/token/verify",
      produces = MediaType.APPLICATION_JSON_VALUE,
      consumes = MediaType.APPLICATION_JSON_VALUE)
  public ResponseEntity<AuthResponseDTO> verifyToken(@RequestBody String token) {
    return ResponseEntity.ok(authClient.verifyToken(token));
  }
}

